// Deep link parameter model
class DeepLinkData {
  final String scheme;
  final String host;
  final List<String> pathSegments;
  final Map<String, String> queryParameters;

  DeepLinkData({
    required this.scheme,
    required this.host,
    required this.pathSegments,
    required this.queryParameters,
  });

  factory DeepLinkData.fromUri(Uri uri) {
    return DeepLinkData(
      scheme: uri.scheme,
      host: uri.host,
      pathSegments: uri.pathSegments,
      queryParameters: uri.queryParameters,
    );
  }

  @override
  String toString() {
    return 'DeepLinkData(scheme: $scheme, host: $host, pathSegments: $pathSegments, queryParameters: $queryParameters)';
  }
}

// Route names
class AppRoutes {
  static const String home = '/';
  static const String profile = '/profile';
  static const String paymentConfirm = '/payment/confirm';
  static const String campaign = '/campaign';
  static const String notification = '/notification';
  static const String unknown = '/unknown';
}

// Router
class AppRouter {
  static Route<dynamic> generateRoute(RouteSettings settings) {
    switch (settings.name) {
      case AppRoutes.home:
        return MaterialPageRoute(builder: (_) => const HomeScreen());

      case AppRoutes.profile:
        final args = settings.arguments as Map<String, dynamic>?;
        final userId = args?['userId'] as String? ?? 'unknown';
        final source = args?['source'] as String? ?? 'direct';
        return MaterialPageRoute(
          builder: (_) => ProfileScreen(userId: userId, source: source),
        );

      case AppRoutes.paymentConfirm:
        final args = settings.arguments as Map<String, dynamic>?;
        final transactionId = args?['transactionId'] as String?;
        final amount = args?['amount'] as String?;
        final status = args?['status'] as String? ?? 'pending';
        return MaterialPageRoute(
          builder: (_) => PaymentConfirmScreen(
            transactionId: transactionId,
            amount: amount,
            status: status,
          ),
        );

      case AppRoutes.campaign:
        final args = settings.arguments as Map<String, dynamic>?;
        final campaignId = args?['campaignId'] as String? ?? 'unknown';
        final source = args?['source'] as String? ?? 'unknown';
        final medium = args?['medium'] as String? ?? 'unknown';
        return MaterialPageRoute(
          builder: (_) => CampaignScreen(
            campaignId: campaignId,
            source: source,
            medium: medium,
          ),
        );

      case AppRoutes.notification:
        final args = settings.arguments as Map<String, dynamic>?;
        final notificationId = args?['notificationId'] as String? ?? 'unknown';
        final type = args?['type'] as String? ?? 'general';
        return MaterialPageRoute(
          builder: (_) => NotificationScreen(
            notificationId: notificationId,
            type: type,
          ),
        );

      default:
        final uri = settings.name ?? 'unknown';
        return MaterialPageRoute(
          builder: (_) => UnknownScreen(route: uri),
        );
    }
  }
}

// Deep Link Handler Singleton
class DeepLinkHandler {
  static final GlobalKey<NavigatorState> navigatorKey =
      GlobalKey<NavigatorState>();

  static StreamSubscription? _linkSubscription;
  static final StreamController<DeepLinkData> _deepLinkStreamController =
      StreamController<DeepLinkData>.broadcast();

  static Stream<DeepLinkData> get deepLinkStream =>
      _deepLinkStreamController.stream;

  // Initialize and handle initial deep link (cold start)
  static Future<DeepLinkData?> initDeepLinks() async {
    DeepLinkData? initialData;

    // Handle the case where the app was started by a deep link
    try {
      final initialLink = await getInitialLink();
      if (initialLink != null) {
        final uri = Uri.parse(initialLink);
        initialData = DeepLinkData.fromUri(uri);
        debugPrint('Initial deep link: $initialData');
        _handleDeepLink(initialData);
      }
    } catch (e) {
      debugPrint('Error getting initial deep link: $e');
    }

    // Handle deep links while the app is running (warm start)
    _linkSubscription = linkStream.listen(
      (String? link) {
        if (link != null) {
          try {
            final uri = Uri.parse(link);
            final data = DeepLinkData.fromUri(uri);
            debugPrint('Received deep link: $data');
            _deepLinkStreamController.add(data);
            _handleDeepLink(data);
          } catch (e) {
            debugPrint('Error parsing deep link: $e');
          }
        }
      },
      onError: (Object err) {
        debugPrint('Deep link stream error: $err');
      },
    );

    return initialData;
  }

  static void _handleDeepLink(DeepLinkData data) {
    final navigator = navigatorKey.currentState;
    if (navigator == null) {
      debugPrint('Navigator not available yet, queuing deep link');
      // Retry after a short delay if navigator isn't ready
      Future.delayed(const Duration(milliseconds: 500), () {
        _handleDeepLink(data);
      });
      return;
    }

    // Parse the deep link and navigate
    final routeInfo = _parseDeepLinkToRoute(data);
    if (routeInfo != null) {
      navigator.pushNamed(
        routeInfo['route'] as String,
        arguments: routeInfo['arguments'] as Map<String, dynamic>?,
      );
    }
  }

  static Map<String, dynamic>? _parseDeepLinkToRoute(DeepLinkData data) {
    // myapp://profile/123?source=campaign
    // myapp://payment/confirm?transaction_id=abc&amount=50.00&status=success
    // myapp://campaign?id=summer2024&source=email&medium=newsletter
    // myapp://notification/view?id=notif123&type=promo

    final host = data.host;
    final pathSegments = data.pathSegments;
    final queryParams = data.queryParameters;

    switch (host) {
      case 'profile':
        final userId =
            pathSegments.isNotEmpty ? pathSegments.first : queryParams['id'] ?? 'unknown';
        return {
          'route': AppRoutes.profile,
          'arguments': {
            'userId': userId,
            'source': queryParams['source'] ?? 'deep_link',
            ...queryParams,
          },
        };

      case 'payment':
        if (pathSegments.isNotEmpty && pathSegments.first == 'confirm') {
          return {
            'route': AppRoutes.paymentConfirm,
            'arguments': {
              'transactionId': queryParams['transaction_id'] ?? queryParams['txn_id'],
              'amount': queryParams['amount'],
              'status': queryParams['status'] ?? 'pending',
              'currency': queryParams['currency'] ?? 'USD',
              ...queryParams,
            },
          };
        }
        return null;

      case 'campaign':
        return {
          'route': AppRoutes.campaign,
          'arguments': {
            'campaignId': queryParams['id'] ?? 'unknown',
            'source': queryParams['source'] ?? queryParams['utm_source'] ?? 'unknown',
            'medium': queryParams['medium'] ?? queryParams['utm_medium'] ?? 'unknown',
            'content': queryParams['content'] ?? queryParams['utm_content'],
            ...queryParams,
          },
        };

      case 'notification':
        final action =
            pathSegments.isNotEmpty ? pathSegments.first : 'view';
        return {
          'route': AppRoutes.notification,
          'arguments': {
            'notificationId': queryParams['id'] ?? 'unknown',
            'type': queryParams['type'] ?? 'general',
            'action': action,
            ...queryParams,
          },
        };

      default:
        debugPrint('Unknown deep link host: $host');
        return {
          'route': AppRoutes.unknown,
          'arguments': {
            'originalHost': host,
            'pathSegments': pathSegments,
            'queryParameters': queryParams,
          },
        };
    }
  }

  // Utility to build a deep link URL
  static String buildDeepLink({
    required String host,
    List<String>? pathSegments,
    Map<String, String>? queryParameters,
  }) {
    final uri = Uri(
      scheme: 'myapp',
      host: host,
      pathSegments: pathSegments,
      queryParameters:
          queryParameters != null && queryParameters.isNotEmpty ? queryParameters : null,
    );
    return uri.toString();
  }

  static void dispose() {
    _linkSubscription?.cancel();
    _deepLinkStreamController.close();
  }
}

// Wrapper widget that initializes deep link handling
class DeepLinkWrapper extends StatefulWidget {
  const DeepLinkWrapper({super.key});

  @override
  State<DeepLinkWrapper> createState() => _DeepLinkWrapperState();
}

class _DeepLinkWrapperState extends State<DeepLinkWrapper> {
  DeepLinkData? _initialDeepLink;
  final List<DeepLinkData> _receivedLinks = [];
  StreamSubscription? _deepLinkSubscription;

  @override
  void initState() {
    super.initState();
    _initDeepLinks();
  }

  Future<void> _initDeepLinks() async {
    final initialData = await DeepLinkHandler.initDeepLinks();
    if (mounted) {
      setState(() {
        _initialDeepLink = initialData;
      });
    }

    _deepLinkSubscription = DeepLinkHandler.deepLinkStream.listen((data) {
      if (mounted) {
        setState(() {
          _receivedLinks.add(data);
        });
      }
    });
  }

  @override
  void dispose() {
    _deepLinkSubscription?.cancel();
    DeepLinkHandler.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return const HomeScreen();
  }
}

